span.t-attf-class:
badge rounded-pill text-bg-#{
                                                'success' if req.stage_id.done else
                                                'secondary' if req.stage_id.fold else
                                                'primary'}

badge rounded-pill text-bg-#{
                                                        'success' if mat.stock_move_id.state == 'done' else
                                                        'warning' if mat.stock_move_id.state == 'assigned' else
                                                        'secondary'}

t.script:
(function () {
    const searchUrl = document.currentScript.dataset.searchUrl;
    const nameInput = document.getElementById('mat_product_name');
    const idInput = document.getElementById('mat_product_id');
    const uomLabel = document.getElementById('mat_product_uom');
    const descInput = document.getElementById('mat_description');
    const submitBtn = document.getElementById('mat_submit_btn');
    const suggestions = document.getElementById('mat_product_suggestions');

    let debounceTimer;

    nameInput.addEventListener('input', function () {
        clearTimeout(debounceTimer);
        idInput.value = '';
        submitBtn.disabled = true;
        const q = this.value.trim();
        if (q.length < 2) {
            suggestions.style.display = 'none';
            suggestions.innerHTML = '';
            return;
        }
        debounceTimer = setTimeout(function () {
            fetch(searchUrl, {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {query: q}}),
            })
            .then(r => r.json())
            .then(data => {
                suggestions.innerHTML = '';
                const results = data.result || [];
                if (!results.length) {
                    suggestions.style.display = 'none';
                    return;
                }
                results.forEach(p => {
                    const item = document.createElement('a');
                    item.href = '#';
                    item.className = 'list-group-item list-group-item-action py-1 px-2 small';
                    item.textContent = p.name + (p.uom ? ' [' + p.uom + ']' : '');
                    item.addEventListener('click', function (e) {
                        e.preventDefault();
                        nameInput.value = p.name;
                        idInput.value = p.id;
                        uomLabel.textContent = p.uom || '';
                        if (!descInput.value) descInput.value = p.name;
                        suggestions.style.display = 'none';
                        submitBtn.disabled = false;
                    });
                    suggestions.appendChild(item);
                });
                suggestions.style.display = 'block';
            })
            .catch(() => { suggestions.style.display = 'none'; });
        }, 250);
    });

    document.addEventListener('click', function (e) {
        if (!suggestions.contains(e.target) && e.target !== nameInput) {
            suggestions.style.display = 'none';
        }
    });
})();

(function () {
    const nameInput = document.getElementById('maint_prod_name');
    const idInput = document.getElementById('maint_prod_id');
    const suggestions = document.getElementById('maint_prod_suggestions');
    if (!nameInput) return;
    let timer;
    nameInput.addEventListener('input', function () {
        clearTimeout(timer);
        const q = this.value.trim();
        if (q.length < 2) { suggestions.style.display = 'none'; return; }
        timer = setTimeout(function () {
            fetch('/my/maintenance/productions/search', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {query: q}}),
            })
            .then(r => r.json())
            .then(data => {
                suggestions.innerHTML = '';
                const results = data.result || [];
                if (!results.length) { suggestions.style.display = 'none'; return; }
                results.forEach(p => {
                    const item = document.createElement('a');
                    item.href = '#';
                    item.className = 'list-group-item list-group-item-action py-1 px-2 small';
                    item.textContent = p.name;
                    item.addEventListener('click', function (e) {
                        e.preventDefault();
                        nameInput.value = p.name;
                        idInput.value = p.id;
                        suggestions.style.display = 'none';
                    });
                    suggestions.appendChild(item);
                });
                suggestions.style.display = 'block';
            })
            .catch(() => { suggestions.style.display = 'none'; });
        }, 250);
    });
    nameInput.addEventListener('blur', function () {
        setTimeout(() => { suggestions.style.display = 'none'; }, 200);
    });
})();

