(function () {
    var check = document.getElementById('new_recurring_check');
    var fields = document.getElementById('new_recurring_fields');
    var repeatType = document.getElementById('new_repeat_type');
    var untilCol = document.getElementById('new_repeat_until_col');
    if (!check) return;
    check.addEventListener('change', function () {
        fields.style.display = this.checked ? 'flex' : 'none';
    });
    repeatType.addEventListener('change', function () {
        untilCol.style.display = this.value === 'until' ? 'block' : 'none';
    });
})();

(function () {
    var check = document.getElementById('maint_new_recurring_check');
    var fields = document.getElementById('maint_new_recurring_fields');
    var repeatType = document.getElementById('maint_new_repeat_type');
    var untilCol = document.getElementById('maint_new_repeat_until_col');
    if (check) {
        check.addEventListener('change', function () {
            fields.style.display = this.checked ? 'flex' : 'none';
        });
        repeatType.addEventListener('change', function () {
            untilCol.style.display = this.value === 'until' ? 'block' : 'none';
        });
    }
    var nameInput = document.getElementById('maint_new_prod_name');
    var idInput = document.getElementById('maint_new_prod_id');
    var suggestions = document.getElementById('maint_new_prod_suggestions');
    if (!nameInput) return;
    var timer;
    nameInput.addEventListener('input', function () {
        clearTimeout(timer);
        var q = this.value.trim();
        if (q.length < 2) { suggestions.style.display = 'none'; return; }
        timer = setTimeout(function () {
            fetch('/my/maintenance/productions/search', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {query: q}}),
            })
            .then(function (r) { return r.json(); })
            .then(function (data) {
                suggestions.innerHTML = '';
                var results = data.result || [];
                if (!results.length) { suggestions.style.display = 'none'; return; }
                results.forEach(function (p) {
                    var item = document.createElement('a');
                    item.href = '#';
                    item.className = 'list-group-item list-group-item-action py-1 px-2 small';
                    item.textContent = p.name;
                    item.addEventListener('click', function (e) {
                        e.preventDefault();
                        nameInput.value = p.name;
                        idInput.value = p.id;
                        suggestions.style.display = 'none';
                    });
                    suggestions.appendChild(item);
                });
                suggestions.style.display = 'block';
            })
            .catch(function () { suggestions.style.display = 'none'; });
        }, 250);
    });
    nameInput.addEventListener('blur', function () {
        setTimeout(function () { suggestions.style.display = 'none'; }, 200);
    });
})();
